package unverified;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairAliasAwareInvocationTestSupport.*;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

class ClonePair7378DifferenceFindingTest {

    private final ClonePair7378 subject = new ClonePair7378();

    /**
     * Generated by Codex (GPT-5).
     * separating case: novel_0_2 ["\" \"", "\"a\""]
     */
    @Test
    void methodsDisagreeOnGeneratedInput() {
        InvocationOutcome method1Outcome = captureWithTimeout(values -> subject.method1((String) values[0], (String) values[1]), 1000L, buildMethod1Inputs());
        InvocationOutcome method2Outcome = captureWithTimeout(values -> subject.method2((String) values[0], (String) values[1]), 1000L, buildMethod2Inputs());

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Boolean(true)",
            null,
            "java.lang.Object[][String(wqA=),String(YQ==)]",
            "java.lang.Object[][String(wqA=),String(YQ==)]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Boolean(false)",
            null,
            "java.lang.Object[][String(wqA=),String(YQ==)]",
            "java.lang.Object[][String(wqA=),String(YQ==)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }

    private Object[] buildMethod1Inputs() {
        return new Object[]{" ", "a"};
    }

    private Object[] buildMethod2Inputs() {
        return new Object[]{" ", "a"};
    }

}
